#requires -Version 5
<#
  sync.ps1 — 從 canonical 正本投影 skills 到各 CLI(Windows junction)

  來源(兩正本的 skills/<domain>/<name>):
    個人 general : $PersonalRoot\skills\general\*
    公司 slot    : $CorpRoot\skills\slot\*
  目標 CLI:
    ~/.kiro/skills, ~/.claude/skills

  安全設計:
    - 預設 DRY-RUN(只印不動)。加 -Apply 才實際執行。
    - 移除既有 junction 用 `rmdir`(只刪連結,不碰正本內容);真實資料夾才用 Remove-Item。
    - 冪等:重跑只會重建連結。
#>
param([switch]$Apply)

$ErrorActionPreference = 'Stop'
$PersonalRoot = 'G:\AI\AI-canonical'
$CorpRoot     = 'G:\AI\AI-canonical-corp'
$Targets = @(
  'C:\Users\jiunchiwang\.kiro\skills',
  'C:\Users\jiunchiwang\.claude\skills'
)
$DryRun = -not $Apply

function Test-Reparse($path){
  $it = Get-Item $path -Force -ErrorAction SilentlyContinue
  return ($it -and ($it.Attributes -band [IO.FileAttributes]::ReparsePoint))
}
function Remove-Target($path){
  if(-not (Test-Path $path)){ return }
  if(Test-Reparse $path){ cmd /c rmdir "$path" | Out-Null }   # junction:只刪連結
  else { Remove-Item $path -Recurse -Force }                   # 真實資料夾
}

# 掃兩個正本,建 skill 名 -> 正本路徑 對照
$sources = @{}
foreach($root in @("$PersonalRoot\skills","$CorpRoot\skills")){
  if(-not (Test-Path $root)){ continue }
  Get-ChildItem $root -Directory | ForEach-Object {           # domain
    Get-ChildItem $_.FullName -Directory | ForEach-Object {   # skill
      if($sources.ContainsKey($_.Name)){ Write-Host ("[warn] 重複 skill 名: " + $_.Name) -ForegroundColor Yellow }
      $sources[$_.Name] = $_.FullName
    }
  }
}

Write-Host ("[mode]    " + $(if($DryRun){'DRY-RUN(只印不動;加 -Apply 才執行)'}else{'APPLY'}))
Write-Host ("[sources] 找到 " + $sources.Count + " 個 skill 正本")

foreach($t in $Targets){
  if(-not (Test-Path $t)){
    if($DryRun){ Write-Host "  [would-mkdir] $t" } else { New-Item -ItemType Directory -Force -Path $t | Out-Null }
  }
  Write-Host "`n=== target: $t ==="
  foreach($name in ($sources.Keys | Sort-Object)){
    $src = $sources[$name]
    $dst = Join-Path $t $name
    $exists = Test-Path $dst
    $isLink = $exists -and (Test-Reparse $dst)
    if($DryRun){
      if($isLink){ Write-Host "  [relink]  $name" }
      elseif($exists){ Write-Host "  [replace] $name  (現為真實資料夾 -> 改 junction)" }
      else { Write-Host "  [link]    $name" }
      continue
    }
    Remove-Target $dst
    cmd /c mklink /J "$dst" "$src" | Out-Null
    Write-Host "  [ok] $name -> $src"
  }
}
# ─── steering(Kiro only;copy 投影 —— 正本為來源,edit 請改正本再 sync)───
$steerSrc = Join-Path $PersonalRoot "steering"
$steerDst = "C:\Users\jiunchiwang\.kiro\steering"
if(Test-Path $steerSrc){
  Write-Host "`n=== steering → $steerDst (copy) ==="
  if(-not (Test-Path $steerDst)){ if(-not $DryRun){ New-Item -ItemType Directory -Force -Path $steerDst | Out-Null } }
  foreach($f in (Get-ChildItem $steerSrc -File -Filter *.md)){
    if($DryRun){ Write-Host "  [would-copy] $($f.Name)" }
    else { Copy-Item $f.FullName (Join-Path $steerDst $f.Name) -Force; Write-Host "  [copied] $($f.Name)" }
  }
}

if($DryRun){ Write-Host "`n完成(DRY-RUN:沒有任何變更。確認後加 -Apply 執行)。" }
else { Write-Host "`n完成(已套用 junction + steering copy)。" }

