foreach ($p in @("C:\Users\jiunchiwang\.kiro\steering\skill-workflow.md","C:\Users\jiunchiwang\.claude\steering\skill-workflow.md")) {
  Write-Output ("$p  =>  " + (Test-Path $p))
}
Write-Output "=== 有任何 CLAUDE.md 引用它嗎? ==="
$candidates = @("C:\Users\jiunchiwang\.claude\CLAUDE.md","G:\Cocos_Project\uk_pirates_queen\CLAUDE.md")
foreach ($c in $candidates) {
  if (Test-Path $c) {
    $hit = Select-String -Path $c -Pattern "skill-workflow|steering" -SimpleMatch -ErrorAction SilentlyContinue
    Write-Output ("$c  =>  " + $(if ($hit) { "命中: " + ($hit.Line -join '; ') } else { "無引用" }))
  }
}
Write-Output "=== ~/.claude 下有沒有 steering 目錄(Claude 根本沒這概念) ==="
Write-Output ("~/.claude/steering 存在? " + (Test-Path "C:\Users\jiunchiwang\.claude\steering"))

